import { Link } from 'react-router-dom';

function Navbar() {
  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <h1>UCU Study Group Finder</h1>
        <span>find your droup learn with ease</span>
      </div>

      <div className="sidebar-user">
        <div className="avatar">SG</div>
        <div className="sidebar-user-text">
          <div className="sidebar-user-name">Study Group User</div>
          <div className="sidebar-user-role">Student</div>
        </div>
      </div>

      <nav className="sidebar-nav">
        <div className="sidebar-label">Navigation</div>
        <Link to="/" className="sidebar-link">Dashboard</Link>
        <Link to="/login" className="sidebar-link">Login</Link>
        <Link to="/register" className="sidebar-link">Register</Link>
        <Link to="/create-group" className="sidebar-link">Create Group</Link>
        <Link to="/chat" className="sidebar-link">Chat</Link>
        <Link to="/session" className="sidebar-link">Session</Link>
      </nav>

      <div className="sidebar-footer">
        <button
          className="sidebar-logout"
          onClick={() => {
            localStorage.removeItem('token');
            window.location.href = '/login';
          }}
        >
          Sign Out
        </button>
      </div>
    </aside>
  );
}

export default Navbar;